{"cmd":"# Let's try to extract text from PDFs using perl with Compress::Zlib
perl -e '
use Compress::Zlib;

my $file = $ARGV[0];
open(my $fh, "<", $file) or die "Cannot open $file: $!";
local $/;
my $content = <$fh>;
close($fh);

# Find all stream...endstream blocks and decompress them
while ($content =~ /stream\n(.*?)endstream/s) {
    my $stream = $1;
    my $decompressed;
    my $z = inflate(init => $stream);
    if ($z) {
        $z->inflate(\$decompressed);
        # Print printable characters
        my $clean = $decompressed;
        $clean =~ s/[^[:print:]\t\n\r]/ /g;
        print "DECOMPRESSED: $clean\n";
    } else {
        print "DEFLATE ERROR: $zlib_err\n";
    }
}
' /app/documents/GFAlpKoFg81H.pdf 2>&1"}

