{"cmd":"perl -e '
use Compress::Zlib;

my $file = $ARGV[0];
open(my $fh, "<", $file) or die "Cannot open $file: $!";
local $/;
my $content = <$fh>;
close($fh);

while ($content =~ /stream\n(.*?)endstream/s) {
    my $stream = $1;
    my $decompressed;
    my $z = new Compress::Zlib::Inflate();
    if ($z) {
        $decompressed = $z->inflate($stream);
        if (defined $decompressed) {
            my $clean = $decompressed;
            $clean =~ s/[^[:print:]\t\n\r]/ /g;
            print "DECOMPRESSED: $clean\n";
        } else {
            print "DEFLATE ERROR: ", $z->status, "\n";
        }
    } else {
        print "INFLATE NEW ERROR\n";
    }
}
' /app/documents/GFAlpKoFg81H.pdf 2>&1"}

